class Solution:
    def minDifficulty(self, jobDifficulty, d):
        n = len(jobDifficulty)
        if n < d:
            return -1
        INF = float('inf')
        dp = [[INF] * (n + 1) for _ in range(d + 1)]
        dp[0][0] = 0
        for day in range(1, d + 1):
            for j in range(day, n - d + day + 1):
                for k in range(day - 1, j):
                    if dp[day - 1][k] == INF:
                        continue
                    cost = max(jobDifficulty[k:j])
                    dp[day][j] = min(dp[day][j], dp[day - 1][k] + cost)
        return dp[d][n] if dp[d][n] != INF else -1

