        prev[0] = 0
        for day in range(1, d + 1):
            curr = [INF] * (n + 1)
            for j in range(day, n + 1):
                max_d = 0
                for k in range(j - 1, day - 2, -1):
                    max_d = max(max_d, jobDifficulty[k])
                    if prev[k] < INF:
                        curr[j] = min(curr[j], prev[k] + max_d)
            prev = curr
        return prev[n] if prev[n] != INF else -1

