var minDifficulty = function(jobDifficulty, d) {
    const n = jobDifficulty.length;
    if (n < d) return -1;
    const INF = Infinity;
    let prev = new Array(n + 1).fill(INF);
    prev[0] = 0;
    for (let day = 1; day <= d; day++) {
        const curr = new Array(n + 1).fill(INF);
        for (let j = day; j <= n; j++) {
            let maxD = 0;
            for (let k = j - 1; k >= day - 1; k--) {
                maxD = Math.max(maxD, jobDifficulty[k]);
                if (prev[k] < INF) curr[j] = Math.min(curr[j], prev[k] + maxD);
            }
        }
        prev = curr;
    }
    return prev[n] === INF ? -1 : prev[n];
};
